/**
 * Data-source taxonomy — every piece of data flowing through the app
 * must be tagged with exactly one of these sources so the UI can
 * display appropriate trust-level badges to the user.
 */

export const DATA_SOURCE = Object.freeze({
  /** Confirmed by telematics hardware / OBD / ECU */
  CONFIRMED_TELEMETRY: 'confirmed_telemetry',

  /** Entered or described by the user (symptoms, codes, free text) */
  USER_REPORTED: 'user_reported',

  /** Generated by an LLM (GPT-4o, Gemini, etc.) */
  MODEL_INFERENCE: 'model_inference',

  /** Pulled from real truck-repair forums via search */
  FORUM_DERIVED: 'forum_derived',

  /** From the local KnowledgeBase / community solutions */
  COMMUNITY_SOLUTION: 'community_solution',

  /** Static reference data (truck specs, code tables, etc.) */
  REFERENCE_DATA: 'reference_data',

  /** Deterministic rule / heuristic (no AI model involved) */
  RULE_HEURISTIC: 'rule_heuristic',

  /** System error — not real data */
  SYSTEM_ERROR: 'system_error',
});

/** Human-readable labels for each source (EN) */
export const DATA_SOURCE_LABEL = Object.freeze({
  [DATA_SOURCE.CONFIRMED_TELEMETRY]: 'Confirmed (Telematics)',
  [DATA_SOURCE.USER_REPORTED]:       'User-Reported',
  [DATA_SOURCE.MODEL_INFERENCE]:     'AI Analysis',
  [DATA_SOURCE.FORUM_DERIVED]:       'Forum / External',
  [DATA_SOURCE.COMMUNITY_SOLUTION]:  'Community',
  [DATA_SOURCE.REFERENCE_DATA]:      'Reference Data',
  [DATA_SOURCE.RULE_HEURISTIC]:      'Rule-Based',
  [DATA_SOURCE.SYSTEM_ERROR]:        'System Error',
});

/** Badge color classes (Tailwind) for each source */
export const DATA_SOURCE_STYLE = Object.freeze({
  [DATA_SOURCE.CONFIRMED_TELEMETRY]: 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30',
  [DATA_SOURCE.USER_REPORTED]:       'bg-blue-500/20 text-blue-400 border-blue-500/30',
  [DATA_SOURCE.MODEL_INFERENCE]:     'bg-purple-500/20 text-purple-400 border-purple-500/30',
  [DATA_SOURCE.FORUM_DERIVED]:       'bg-orange-500/20 text-orange-400 border-orange-500/30',
  [DATA_SOURCE.COMMUNITY_SOLUTION]:  'bg-cyan-500/20 text-cyan-400 border-cyan-500/30',
  [DATA_SOURCE.REFERENCE_DATA]:      'bg-gray-500/20 text-gray-400 border-gray-500/30',
  [DATA_SOURCE.RULE_HEURISTIC]:      'bg-yellow-500/20 text-yellow-400 border-yellow-500/30',
  [DATA_SOURCE.SYSTEM_ERROR]:        'bg-red-500/20 text-red-400 border-red-500/30',
});
